// And groups predicates with the AND operator between them.
func And(predicates ...predicate.NoteConnectionAccount) predicate.NoteConnectionAccount {
	return predicate.NoteConnectionAccount(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.NoteConnectionAccount) predicate.NoteConnectionAccount {
	return predicate.NoteConnectionAccount(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.NoteConnectionAccount) predicate.NoteConnectionAccount {
	return predicate.NoteConnectionAccount(sql.NotPredicates(p))
}
